/** 社交卡片类型 Logo（右下角装饰） */
function SocialTypeLogo({ size = 18 }: { size?: number }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round">
      <path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2" />
      <circle cx="9" cy="7" r="4" />
      <path d="M22 21v-2a4 4 0 0 0-3-3.87" />
      <path d="M16 3.13a4 4 0 0 1 0 7.75" />
    </svg>
  );
}

export function SocialCardContent({
  card,
  editable,
  draggable,
  onEdit,
  onDelete,
  enterDelay,
  dragHandleProps,
  themeMode,
  wallpaperAware,
  onCardClick,
}: {
  card: SocialCard;
  editable: boolean;
  draggable: boolean;
  onEdit?: () => void;
  onDelete?: () => void;
  enterDelay?: string;
  dragHandleProps?: Record<string, unknown>;
  themeMode?: ThemeMode;
  wallpaperAware?: boolean;
  onCardClick?: () => void;
}) {
  const isDark = themeMode === "dark";

  const textShadowClass = wallpaperAware
    ? themeMode === "light"
      ? "drop-shadow-[0_1px_2px_rgba(0,0,0,0.2)]"
      : "drop-shadow-[0_1px_3px_rgba(0,0,0,0.4)]"
    : "";

  /** Logo 图标：自定义 URL 或品牌 SVG，无方形外框，尺寸放大 */
  const logoElement = card.iconUrl ? (
    // eslint-disable-next-line @next/next/no-img-element
    <img src={card.iconUrl} alt={card.label} className="h-full w-full object-contain" />
  ) : (
    <div className="flex h-full w-full items-center justify-center">
      <CardTypeIcon cardType={card.cardType} size={56} />
    </div>
  );

  return (
    <div
      className="animate-card-enter relative flex h-full cursor-pointer flex-col items-center gap-0 pt-0.5"
      style={enterDelay ? { animationDelay: enterDelay } : undefined}
      onClick={onCardClick}
    >
      {/* 共用卡片头部：编辑按钮 + 拖拽手柄 + 删除按钮 */}
      <CardHeader
        editable={editable}
        draggable={draggable}
        themeMode={themeMode ?? "light"}
        wallpaperAware={wallpaperAware ?? false}
        dragHandleProps={draggable ? dragHandleProps : undefined}
        onEdit={onEdit}
        onDelete={onDelete}
      />

      {/* Logo：放大居中 */}
      <div className="mt-2 h-16 w-16 shrink-0">
        {logoElement}
      </div>

      {/* 提示文字：始终占位以保持标题位置固定，内容仅在有自定义文字时可见 */}
      <p className={cn(
        "w-full truncate text-center text-sm leading-snug",
        card.hint ? (isDark ? "text-white/60" : "text-slate-500") : "invisible",
        card.hint && wallpaperAware ? textShadowClass : "",
      )}>
        {card.hint || "placeholder"}
      </p>

      {/* 标题：居中 */}
      <h3 className={cn(
        "mt-2 truncate font-semibold tracking-tight text-2xl",
        textShadowClass,
      )}>
        {card.label}
      </h3>

      {/* 右下角类型 Logo */}
      <div className="mt-auto flex w-full justify-end">
        <div className={cn(
          "shrink-0 opacity-30",
          isDark ? "text-white/40" : "text-slate-400",
        )}>
          <SocialTypeLogo size={18} />
        </div>
      </div>
    </div>
  );
}
